-- Seed organizations from projects CSV
ON CONFLICT (organization_id) DO NOTHING;

-- Seed problems from problems CSV
ON CONFLICT (problem_id) DO NOTHING;

-- Seed solutions from solutions CSV
ON CONFLICT (solution_id) DO NOTHING;

SELECT setval(pg_get_serial_sequence('public.organizations', 'organization_id'), COALESCE((SELECT MAX(organization_id) FROM public.organizations), 1), true);
SELECT setval(pg_get_serial_sequence('public.problems', 'problem_id'), COALESCE((SELECT MAX(problem_id) FROM public.problems), 1), true);
SELECT setval(pg_get_serial_sequence('public.solutions', 'solution_id'), COALESCE((SELECT MAX(solution_id) FROM public.solutions), 1), true);
